class MobileNavManager{constructor(){this.navbarToggler=document.querySelector('.navbar-toggler');this.navbarCollapse=document.querySelector('.navbar-collapse');this.navItems=document.querySelectorAll('.navbar-nav .nav-link');this.dropdownToggles=document.querySelectorAll('.navbar-nav .dropdown-toggle');this.isOpen=false;this.isMobile=window.innerWidth<=768;this.init();}init(){if(this.navbarToggler){this.navbarToggler.addEventListener('click',(e)=>{e.preventDefault();this.toggle();});}if(this.isMobile){document.querySelectorAll('[data-mobile-dropdown]').forEach(dropdown=>{dropdown.removeAttribute('data-bs-toggle');const dropdownInstance=bootstrap.Dropdown.getInstance(dropdown);if(dropdownInstance){dropdownInstance.dispose();}});}this.setupBackdrop();document.addEventListener('click',(e)=>{const toggle=e.target.closest('[data-mobile-dropdown]');if(toggle&&toggle.classList.contains('dropdown-toggle')&&this.isMobile){e.preventDefault();e.stopPropagation();e.stopImmediatePropagation();console.log('🔴 Dropdown toggle clicked:',toggle.textContent.trim());const parent=toggle.closest('.nav-item');if(!parent){console.warn('No nav-item parent found for dropdown toggle');return;}const menu=parent.querySelector('.dropdown-menu');if(!menu){console.warn('No dropdown-menu found in parent');return;}document.querySelectorAll('.navbar-nav .dropdown-menu.show').forEach(otherMenu=>{if(otherMenu!==menu){otherMenu.classList.remove('show');const otherToggle=otherMenu.parentElement.querySelector('[data-mobile-dropdown]');if(otherToggle){otherToggle.setAttribute('aria-expanded','false');}}});const wasOpen=menu.classList.contains('show');menu.classList.toggle('show');const isNowOpen=menu.classList.contains('show');toggle.setAttribute('aria-expanded',isNowOpen ? 'true':'false');console.log(`✅ Dropdown toggled:"${toggle.textContent.trim()}"|Was:${wasOpen ? 'OPEN':'CLOSED'}→ Now:${isNowOpen ? 'OPEN':'CLOSED'}`);return false;}},true);document.addEventListener('click',(e)=>{const link=e.target.closest('.navbar-nav .nav-link:not(.dropdown-toggle)');if(link&&this.isMobile&&this.isOpen){setTimeout(()=>{this.close();},100);}});document.addEventListener('click',(e)=>{const item=e.target.closest('.navbar-nav .dropdown-item');const toggle=e.target.closest('[data-mobile-dropdown]');if(item&&!toggle&&this.isMobile){e.stopPropagation();console.log('📌 Dropdown item clicked,closing drawer');setTimeout(()=>{this.close();},100);}});window.addEventListener('resize',()=>{this.handleResize();});if(typeof feather!=='undefined'){feather.replace();}}setupBackdrop(){let backdrop=document.querySelector('.navbar-backdrop');if(!backdrop){backdrop=document.createElement('div');backdrop.className='navbar-backdrop';document.body.insertBefore(backdrop,document.querySelector('.navbar'));}backdrop.addEventListener('click',()=>this.close());}toggle(){if(this.isOpen){this.close();}else{this.open();}}open(){if(!this.isMobile)return;this.isOpen=true;this.navbarCollapse.classList.add('show');const backdrop=document.querySelector('.navbar-backdrop');if(backdrop){backdrop.classList.add('show');}document.body.classList.add('drawer-open');if(this.navbarToggler){this.navbarToggler.setAttribute('aria-expanded','true');}}close(){this.isOpen=false;this.navbarCollapse.classList.remove('show');const backdrop=document.querySelector('.navbar-backdrop');if(backdrop){backdrop.classList.remove('show');}document.body.classList.remove('drawer-open');document.querySelectorAll('.navbar-nav .dropdown-menu.show').forEach(menu=>{menu.classList.remove('show');});this.dropdownToggles.forEach(toggle=>{toggle.setAttribute('aria-expanded','false');});if(this.navbarToggler){this.navbarToggler.setAttribute('aria-expanded','false');}}handleResize(){const wasMobile=this.isMobile;this.isMobile=window.innerWidth<=768;if(wasMobile&&!this.isMobile){this.close();this.navbarCollapse.classList.remove('show');}}}document.addEventListener('DOMContentLoaded',()=>{new MobileNavManager();});